-- SQL Server Database Creation
-- Traditional approach using T-SQL commands

-- 1. Connect to SQL Server instance
-- sqlcmd -S localhost -E
-- Or use SQL Server Management Studio (SSMS)

-- 2. Create new database with custom settings
CREATE DATABASE MyAppDB
ON (
    NAME = 'MyAppDB',
    FILENAME = 'C:\Program Files\Microsoft SQL Server\MSSQL15.MSSQLSERVER\MSSQL\DATA\MyAppDB.mdf',
    SIZE = 100MB,
    MAXSIZE = 1GB,
    FILEGROWTH = 10MB
)
LOG ON (
    NAME = 'MyAppDB_Log',
    FILENAME = 'C:\Program Files\Microsoft SQL Server\MSSQL15.MSSQLSERVER\MSSQL\DATA\MyAppDB_Log.ldf',
    SIZE = 10MB,
    MAXSIZE = 100MB,
    FILEGROWTH = 10%
);

-- 3. Set database options
ALTER DATABASE MyAppDB SET RECOVERY FULL;
ALTER DATABASE MyAppDB SET AUTO_CREATE_STATISTICS ON;
ALTER DATABASE MyAppDB SET AUTO_UPDATE_STATISTICS ON;

-- 4. Create application user
USE MyAppDB;
CREATE LOGIN app_user WITH PASSWORD = 'SecurePassword123!';
CREATE USER app_user FOR LOGIN app_user;
ALTER ROLE db_datareader ADD MEMBER app_user;
ALTER ROLE db_datawriter ADD MEMBER app_user;

-- 5. Verify configuration
SELECT name, database_id, create_date, collation_name
FROM sys.databases
WHERE name = 'MyAppDB';

-- SQL Server Development Environment Setup
-- Traditional approach with multiple instances or databases

-- 1. Development Database Setup
CREATE DATABASE MyApp_Development
ON (
    NAME = 'MyApp_Dev',
    FILENAME = 'C:\SQL_Data\MyApp_Development.mdf',
    SIZE = 100MB
)
LOG ON (
    NAME = 'MyApp_Dev_Log',
    FILENAME = 'C:\SQL_Data\MyApp_Development_Log.ldf',
    SIZE = 10MB
);

-- 2. Testing Database Setup
CREATE DATABASE MyApp_Testing
ON (
    NAME = 'MyApp_Test',
    FILENAME = 'C:\SQL_Data\MyApp_Testing.mdf',
    SIZE = 100MB
)
LOG ON (
    NAME = 'MyApp_Test_Log',
    FILENAME = 'C:\SQL_Data\MyApp_Testing_Log.ldf',
    SIZE = 10MB
);

-- 3. Environment-specific configurations
-- Development: Full logging, relaxed security
ALTER DATABASE MyApp_Development SET RECOVERY FULL;
ALTER DATABASE MyApp_Development SET AUTO_CREATE_STATISTICS ON;

-- Testing: Optimized for automated testing
ALTER DATABASE MyApp_Testing SET RECOVERY SIMPLE;
ALTER DATABASE MyApp_Testing SET AUTO_SHRINK ON;

-- 4. User management per environment
-- Development users
USE MyApp_Development;
CREATE USER dev_user FOR LOGIN dev_login;
ALTER ROLE db_owner ADD MEMBER dev_user;

-- Testing users
USE MyApp_Testing;
CREATE USER test_user FOR LOGIN test_login;
ALTER ROLE db_datareader ADD MEMBER test_user;
ALTER ROLE db_datawriter ADD MEMBER test_user;

-- 5. Environment switching in application config
-- <connectionStrings>
--   <add name="Development"
--        connectionString="Server=localhost;Database=MyApp_Development;Integrated Security=true;" />
--   <add name="Testing"
--        connectionString="Server=localhost;Database=MyApp_Testing;Integrated Security=true;" />
-- </connectionStrings>

-- 6. Database refresh for testing
-- Restore development data to testing environment
BACKUP DATABASE MyApp_Development
TO DISK = 'C:\Temp\DevData.bak' WITH COMPRESSION;

RESTORE DATABASE MyApp_Testing
FROM DISK = 'C:\Temp\DevData.bak'
WITH REPLACE,
     MOVE 'MyApp_Dev' TO 'C:\SQL_Data\MyApp_Testing.mdf',
     MOVE 'MyApp_Dev_Log' TO 'C:\SQL_Data\MyApp_Testing_Log.ldf';
